// build.gradle: implementation 'com.auth0:java-jwt:4.4.0'

import com.auth0.jwt.JWT;
import com.auth0.jwt.algorithms.Algorithm;
import com.auth0.jwt.interfaces.DecodedJWT;

public class TokenService {
  private final Algorithm algorithm;
  private final String issuer = "https://auth.example.com";
  private final String audience = "api.example.com";

  public TokenService(String secret) {
    // For HS256. For RS256, use Algorithm.RSA256(publicKey, privateKey).
    this.algorithm = Algorithm.HMAC256(secret);
  }

  // ============ ISSUE ============
  public String issueAccessToken(long userId, Set<String> scopes) {
    return JWT.create()
        .withIssuer(issuer)
        .withAudience(audience)
        .withSubject(String.valueOf(userId))
        .withClaim("scope", String.join(" ", scopes))
        .withIssuedAt(Instant.now())
        .withExpiresAt(Instant.now().plus(15, ChronoUnit.MINUTES))   // short-lived!
        .withJWTId(UUID.randomUUID().toString())
        .sign(algorithm);
  }

  // ============ VERIFY ============
  public DecodedJWT verify(String token) {
    var verifier = JWT.require(algorithm)
        .withIssuer(issuer)
        .withAudience(audience)   // reject tokens meant for another API
        .acceptLeeway(30)         // 30-second clock skew tolerance
        .build();
    return verifier.verify(token);   // throws if signature/expiry/issuer/audience fails
  }
}

// Usage in a filter or Resource Server
var decoded = tokenService.verify(bearerToken);
var userId = Long.parseLong(decoded.getSubject());
var scopes = Set.of(decoded.getClaim("scope").asString().split(" "));

